// Cell represents a cell in the grid for priority queue use.
type Cell struct {
	r int64
	c int64
	d int64 // distance from the nearest source
	color int64
}

// PriorityQueue implements heap.Interface and holds Cells.
type PriorityQueue []*Cell

func (pq PriorityQueue) Len() int { return len(pq) }

// Min-Heap based on distance 'd'. If distances are equal, use color for tie-breaking
// (though the problem logic implies BFS structure handles time implicitly,
// we need a way to prioritize expansion). Since we are looking for the *fastest* arrival,
// distance 'd' is the primary key.
// The problem implies that if multiple colors arrive at time T, the max color wins.
// A standard BFS processes layer by layer (time step by time step).
// The priority queue structure here needs to ensure we process cells in increasing order of arrival time (distance).
func (pq PriorityQueue) Less(i, j int) bool {
	// Primary sorting: smaller distance comes first (earlier arrival)
	if pq[i].d != pq[j].d {
		return pq[i].d < pq[j].d
	}
	// Secondary sorting: larger color wins in case of simultaneous arrival (though this is handled by the update logic)
	// For the PQ itself, a consistent ordering is needed. Let's prioritize smaller color if distances are equal,
	// though the core logic relies on the relaxation/update process.
	// In a standard Dijkstra/Multi-source BFS, tie-breaking isn't strictly necessary for correctness if updates handle conflicts.
	// Here, we prioritize the one with the larger color among those reaching at the same time, to potentially settle the conflict earlier,
	// although the final assignment must rely on the maximum color encountered.
	return pq[i].color > pq[j].color
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Cell)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, m int64, sources [][]int64) [][]int64 {
	// Initialize the grid: color 0 means uncolored.
	grid := make([][]int64, n)
	for i := int64(0); i < n; i++ {
		grid[i] = make([]int64, m)
	}

	// Initialize distance grid: infinity for unreached, 0 for sources.
	// Since the max possible distance is n+m-2, math.MaxInt64 is safe for infinity.
	dist := make([][]int64, n)
	for i := int64(0); i < n; i++ {
		dist[i] = make([]int64, m)
		for j := int64(0); j < m; j++ {
			dist[i][j] = math.MaxInt64
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// Initialize sources
	for _, source := range sources {
		r, c, color := source[0], source[1], source[2]

		// Set initial state
		grid[r][c] = color
		dist[r][c] = 0

		// Push to PQ
		cell := &Cell{r: r, c: c, d: 0, color: color}
		heap.Push(&pq, cell)
	}

	directions := [][]int64{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}

	// Dijkstra-like Multi-Source BFS
	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Cell)
		r, c, d, color := current.r, current.c, current.d, current.color

		// Optimization: If we found a strictly faster path to this cell already, skip.
		// Since we prioritize by distance in PQ, this mainly handles stale entries.
		if d > dist[r][c] {
			continue
		}

		// Crucial check: If the current cell's recorded color in the grid is greater than
		// the color associated with the path popped from PQ, it means a later-popped
		// (but potentially faster arrival) path resulted in a higher color at this spot,
		// or the initial setting was already overwritten by a better color.
		// However, the distance check (d > dist[r][c]) handles the time aspect.
		// We must ensure the grid color reflects the maximum color seen for that minimum time.

		// Since we update the grid color upon arrival, if the popped color is less than
		// the grid color, it means a higher color reached this cell earlier or at the same time
		// and was already processed/recorded as the final color.
		if color < grid[r][c] {
			// If the color popped is strictly less than the color currently in the grid,
			// it implies the cell was already finalized with a higher color (or the same color
			// via a path that was processed first), so we skip propagation from this lesser-colored path.
			continue
		}


