		for _, dir := range directions {
			nr, nc := r+dir[0], c+dir[1]

			// Check bounds
			if nr >= 0 && nr < n && nc >= 0 && nc < m {

				newDist := d + 1

				// Relaxation/Update logic

				// 1. If unvisited (or reached later)
				if newDist < dist[nr][nc] {
					dist[nr][nc] = newDist

