					// Simultaneous arrival: choose the maximum color
					if color > currentColor {
						// New color is better (larger)
						finalColor[nr][nc] = color
						// Push to PQ to propagate this new, better color outwards
						// Note: We don't strictly need to update dist here since it's the same,
						// but we push to ensure propagation with the higher color.
						heap.Push(&pq, &Item{
